const body = $input.first().json.body ?? $input.first().json;
const { sequence_id, step_id, status, sync_appointment = true, notify_patient = false } = body;

const VALID_STATUSES = ['pending', 'scheduled', 'completed', 'cancelled', 'missed'];
if (!sequence_id) throw new Error('sequence_id is required');
if (!step_id) throw new Error('step_id is required');
if (!VALID_STATUSES.includes(status)) throw new Error(`Invalid status: ${status}`);

// Map step status to appointment/milestone status
const apptStatusMap = {
  completed: { appt_status: 'completed', milestone: 'done' },
  cancelled: { appt_status: 'cancelled', milestone: null },
  missed:    { appt_status: null,        milestone: 'alert' },
  pending:   { appt_status: null,        milestone: 'waiting' },
  scheduled: { appt_status: null,        milestone: 'waiting' },
};
const mapping = apptStatusMap[status];

return [{ json: { sequence_id, step_id, status, sync_appointment: !!sync_appointment, notify_patient: !!notify_patient, mapping } }];

const { sequence_id, step_id, status, sync_appointment, mapping } = $input.first().json;

// Set completed_at for completed status
const completedAt = status === 'completed' ? 'NOW()' : 'NULL';

// Update the step
const updateStepSQL = `
  UPDATE treatment_steps
  SET status = '${status}', completed_at = ${completedAt}, updated_at = NOW()
  WHERE id = '${step_id}' AND sequence_id = '${sequence_id}'
  RETURNING id, sequence_id, step_number, step_name, scheduled_date::text, duration_minutes, status, notes, appointment_id, completed_at::text;
`;

// Sync appointment if needed
let syncApptSQL = '';
if (sync_appointment) {
  if (mapping.appt_status) {
    syncApptSQL = `
      UPDATE appointments
      SET status = '${mapping.appt_status}', milestone_status = ${mapping.milestone ? `'${mapping.milestone}'` : 'NULL'}
      WHERE id = (SELECT appointment_id FROM treatment_steps WHERE id = '${step_id}' AND appointment_id IS NOT NULL);
    `;
  } else if (mapping.milestone) {
    syncApptSQL = `
      UPDATE appointments
      SET milestone_status = '${mapping.milestone}'
      WHERE id = (SELECT appointment_id FROM treatment_steps WHERE id = '${step_id}' AND appointment_id IS NOT NULL);
    `;
  }
}

// Check if all non-cancelled steps are completed → auto-complete sequence
const autoCompleteSQL = `
  UPDATE treatment_sequences
  SET status = 'completed', updated_at = NOW()
  WHERE id = '${sequence_id}'
    AND NOT EXISTS (
      SELECT 1 FROM treatment_steps
      WHERE sequence_id = '${sequence_id}'
        AND status NOT IN ('completed', 'cancelled')
    );
`;

return [{ json: { sequence_id, step_id, status, updateStepSQL, syncApptSQL, autoCompleteSQL } }];

const rows = $input.all();
if (rows.length === 0) throw new Error('Step not found after update');
const r = rows[0].json;
return [{ json: {
  success: true,
  step: {
    id: r.id,
    sequence_id: r.sequence_id,
    step_number: r.step_number,
    step_name: r.step_name,
    scheduled_date: r.scheduled_date || null,
    duration_minutes: r.duration_minutes,
    status: r.status,
    notes: r.notes || null,
    appointment_id: r.appointment_id || null,
    completed_at: r.completed_at || null,
  },
  sequence_completed: r.sequence_status === 'completed',
} }];
